            put( "Canceled", "canceled" );
            put( "PendingCancel", "open" );
            put( "PendingNew", "open" );
            put( "Rejected", "rejected" );
            put( "Expired", "expired" );
            put( "Stopped", "open" );
            put( "Untriggered", "open" );
            put( "Triggered", "open" );
